<?php
namespace Tests\Unit\Domain\Combat;use App\Domain\Combat\CombatActionResolver;use App\Domain\Combat\CombatResultStatus;use App\Domain\Combat\CombatSimulator;use App\Domain\Combat\Data\CombatantStats;use App\Domain\Random\RandomNumberGenerator;use PHPUnit\Framework\TestCase;class SequenceRandom implements RandomNumberGenerator{public $values;public $calls=0;public function __construct(array $v){$this->values=$v;}public function randomInt(int $min,int $max):int{$this->calls++;return array_shift($this->values);} }class CombatSimulatorTest extends TestCase{private function c($id,$health=20,$attack=10,$speed=1,$accuracy=0,$evasion=0,$critical=0,$multiplier=1.5,$reduction=0){return new CombatantStats($id,$id,$health,$health,$attack,0,$accuracy,$evasion,$critical,$multiplier,$speed,$reduction);}private function simulator($rng){return new CombatSimulator(new CombatActionResolver($rng));}public function test_boundaries_and_compatibility(){$rng=new SequenceRandom(array_merge([8000,10000,8001,10000],array_fill(0,400,10000)));$r=$this->simulator($rng)->simulate($this->c('character',20,1,1,10),$this->c('monster',20,1,1,0,5));$a=$r->rounds()[0]->actions();$this->assertTrue($a[0]->hit());$this->assertFalse($a[1]->hit());$this->assertNull($a[1]->criticalRoll());}public function test_first_actor_kill_has_one_action(){$r=$this->simulator(new SequenceRandom([1,1]))->simulate($this->c('character',20,5,2,0,0,100,1.5),$this->c('monster',6,1,1,0,0,0,1.5,10));$this->assertSame(7,$r->rounds()[0]->actions()[0]->damage());$this->assertSame(CombatResultStatus::CHARACTER_VICTORY,$r->status());$this->assertCount(1,$r->rounds()[0]->actions());}public function test_initial_defeats_consume_no_rng(){foreach([[0,10,CombatResultStatus::MONSTER_VICTORY],[10,0,CombatResultStatus::CHARACTER_VICTORY],[0,0,CombatResultStatus::DRAW]] as $x){$rng=new SequenceRandom([]);$r=$this->simulator($rng)->simulate(new CombatantStats('c','c',20,$x[0],1,0,0,0,0,1,1,0),new CombatantStats('m','m',20,$x[1],1,0,0,0,0,1,1,0));$this->assertSame($x[2],$r->status());$this->assertSame(0,$r->roundsCount());$this->assertSame(0,$rng->calls);}}public function test_draw_stops_after_round_100(){$rng=new SequenceRandom(array_fill(0,200,10000));$r=$this->simulator($rng)->simulate($this->c('c',1000,0),$this->c('m',1000,0));$this->assertSame(CombatResultStatus::DRAW,$r->status());$this->assertSame(100,$r->roundsCount());$this->assertSame(200,$rng->calls);}}
